create table dirkspzm32.isi_scanner_funk_cfg (
    sid                       varchar2(2 char) not null enable,
    firma_nr                  number(6, 0) not null enable,
    scanner_funk_name         varchar2(255 char) not null enable,
    scanner_funk_prae         varchar2(15 char),
    scanner_funk_post         varchar2(15 char),
    scanner_funk_delimiter    varchar2(15 char),
    scanner_funk_typ          varchar2(15 char),
    com_name                  varchar2(15 char),
    scanner_funk_visuname     varchar2(15 char),
    appli_modul               varchar2(30 char),
    appli_funktion            varchar2(30 char),
    appli_service             varchar2(30 char),
    scanner_funk_init_str     varchar2(50 char),
    scanner_funk_init_antwort number(*, 12),
    scanner_funk_enabled      varchar2(1 char)
);

alter table dirkspzm32.isi_scanner_funk_cfg
    add constraint pk_scanner_funk_cfg
        primary key ( sid,
                      firma_nr,
                      scanner_funk_name )
            using index enable;


